function RegSet($path, $name, $value, $type = "DWord") {
    If (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
    Set-ItemProperty -Path $path -Name $name -Value $value -Type $type -EA SilentlyContinue
}
function SvcKill($name) {
    $s = Get-Service -Name $name -EA SilentlyContinue
    If ($s) {
        Stop-Service    $name -Force           -EA SilentlyContinue
        Set-Service     $name -StartupType Disabled -EA SilentlyContinue
        sc.exe config   $name start= disabled  2>$null | Out-Null
    }
}
function SvcEnable($name, $startType = "Automatic") {
    $s = Get-Service -Name $name -EA SilentlyContinue
    If ($s) {
        Set-Service  $name -StartupType $startType -EA SilentlyContinue
        sc.exe config $name start= auto 2>$null | Out-Null
        Start-Service $name -EA SilentlyContinue
    }
}

function Invoke-UltraNetTcpGlobal {
    netsh int tcp set heuristics disabled 2>$null | Out-Null
    @(
        'chimney=disabled',
        'rss=enabled',
        'autotuninglevel=disabled',
        'rsc=disabled',
        'ecncapability=disabled',
        'timestamps=disabled',
        'initialrto=1500',
        'maxsynretransmissions=2',
        'nonsackrttresiliency=disabled',
        'fastopen=enabled',
        'fastopenfallback=enabled',
        'hystart=disabled',
        'pacingprofile=off',
        'loopbackfastpath=enabled',
        'maxsegmentretransmissions=2'
    ) | ForEach-Object { netsh int tcp set global $_ 2>$null | Out-Null }
    netsh int tcp set global dca=enabled             2>$null | Out-Null
    netsh int tcp set supplemental template=internet congestionprovider=ctcp 2>$null | Out-Null
    netsh int tcp set global minrto=300              2>$null | Out-Null
    netsh interface ipv6 set global randomizeidentifiers=disabled 2>$null | Out-Null
}
function Set-InterfaceNagleOff {
    Get-ChildItem "HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip\Parameters\Interfaces" -EA SilentlyContinue | ForEach-Object {
        Set-ItemProperty $_.PSPath "TcpAckFrequency" 1 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $_.PSPath "TCPNoDelay"      1 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $_.PSPath "TcpDelAckTicks"  0 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $_.PSPath "MTU"             1500 -Type DWord -EA SilentlyContinue
    }
}
function Set-CitizenFXNetUltra {
    $c = "HKCU:\SOFTWARE\CitizenFX"
    $n = "HKCU:\SOFTWARE\CitizenFX\Network"
    If (-not (Test-Path $c)) { New-Item $c -Force | Out-Null }
    If (-not (Test-Path $n)) { New-Item $n -Force | Out-Null }
    RegSet $c "net_maxPackets"               "128"       "String"
    RegSet $c "net_showCondition"            "0"         "String"
    RegSet $c "game_enforcegameencryption"   "0"         "String"
    RegSet $c "cl_preferIPv6"               "0"         "String"
    RegSet $c "game_enableFPSLimit"          "0"         "String"
    RegSet $c "ui_disableMusicTheme"         "1"         "String"
    RegSet $c "cl_drawFps"                   "0"         "String"
    RegSet $c "net_statsFile"               ""          "String"
    RegSet $c "net_logFile"                 ""          "String"
    RegSet $c "cl_disableAlternateSkins"     "1"         "String"
    # ต่อตรง server ไม่ผ่าน relay -- ลด hop/jitter
    RegSet $c "net_routing"                  "0"         "String"
    # resync เร็วขึ้นเมื่อ packet มาผิดลำดับ -- ลด desync/ผี
    RegSet $c "net_ooPacketThreshold"        "1"         "String"
    RegSet $n "netFrameTime"                 "0"         "String"
    RegSet $n "netTimeout"                   "45000"     "String"
    RegSet $n "netRateThreshold"             "0"         "String"
    # ลด retransmit timeout 350->200ms
    RegSet $n "netReliableRetransmitTimeout" "200"       "String"
    RegSet $n "UseNewFrameScheduler"         "1"         "String"
    RegSet $n "netPacketLossThreshold"       "0"         "String"
    # เพิ่ม bandwidth 100MB->200MB
    RegSet $n "netBandwidthIn"              "209715200" "String"
    RegSet $n "netBandwidthOut"             "209715200" "String"
}

